class Solution {
    public boolean checkSubarraySum(int[] nums, int k) {
        int n = nums.length;
        if (n < 2) return false;

        int[] sum = new int[n + 1];
        for (int i = 0; i < n; i++) {
            sum[i + 1] = sum[i] + nums[i];
        }

        for (int i = 0; i < n; i++) {
            for (int j = i + 2; j <= n; j++) {
                if ((sum[j] - sum[i]) % k == 0) return true;
            }
        }

        return false;
    }
}
